import{_ as d,o as a,c as e,a4 as r}from"./chunks/framework.ChErgFjV.js";const u=JSON.parse('{"title":"第六章 中学心理辅导","description":"","frontmatter":{"title":"第六章 中学心理辅导","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter6.md","filePath":"study/teacher-cert/education-knowledge/chapter6.md","lastUpdated":null}'),l={name:"study/teacher-cert/education-knowledge/chapter6.md"};function o(i,t,h,n,s,b){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="第六章-中学心理辅导" tabindex="-1">第六章 中学心理辅导 <a class="header-anchor" href="#第六章-中学心理辅导" aria-label="Permalink to &quot;第六章 中学心理辅导&quot;">​</a></h1><blockquote><p>本章考情：选择题为主，约 4-6 分 重点：心理健康标准、常见心理问题、辅导方法</p></blockquote><hr><h2 id="_6-1-心理健康标准-🔴" tabindex="-1">6.1 心理健康标准 🔴 <a class="header-anchor" href="#_6-1-心理健康标准-🔴" aria-label="Permalink to &quot;6.1 心理健康标准 🔴&quot;">​</a></h2><ol><li>智力正常 — 最基本条件</li><li>情绪稳定乐观</li><li>意志健全</li><li>人格完整和谐</li><li>自我意识正确</li><li>人际关系良好</li><li>社会适应良好</li><li>心理行为符合年龄特征</li></ol><p><strong>辨析</strong> 🔴：</p><ul><li>&quot;心理健康就是没有心理疾病&quot; → ❌ 心理健康不仅是没有疾病，还包括积极的心理状态</li><li>&quot;心理健康是一成不变的&quot; → ❌ 心理健康是动态的、相对的</li></ul><hr><h2 id="_6-2-常见心理问题-🔴🔴" tabindex="-1">6.2 常见心理问题 🔴🔴 <a class="header-anchor" href="#_6-2-常见心理问题-🔴🔴" aria-label="Permalink to &quot;6.2 常见心理问题 🔴🔴&quot;">​</a></h2><h3 id="焦虑症-🔴🔴" tabindex="-1">焦虑症 🔴🔴 <a class="header-anchor" href="#焦虑症-🔴🔴" aria-label="Permalink to &quot;焦虑症 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>表现</td><td>过度担忧、紧张不安、心悸、出汗、失眠</td></tr><tr><td>类型</td><td>考试焦虑🔴、社交焦虑、广泛性焦虑</td></tr><tr><td>辅导方法</td><td>放松训练🔴、系统脱敏法、认知疗法</td></tr></tbody></table><h3 id="抑郁症-🔴" tabindex="-1">抑郁症 🔴 <a class="header-anchor" href="#抑郁症-🔴" aria-label="Permalink to &quot;抑郁症 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>核心症状</td><td>情绪低落、兴趣丧失、精力减退</td></tr><tr><td>伴随症状</td><td>失眠/嗜睡、食欲变化、自我评价低</td></tr><tr><td>辅导方法</td><td>认知行为疗法、支持性心理治疗、及时转介</td></tr></tbody></table><h3 id="强迫症-🔴" tabindex="-1">强迫症 🔴 <a class="header-anchor" href="#强迫症-🔴" aria-label="Permalink to &quot;强迫症 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>表现</td><td>强迫观念（反复出现的不合理想法）+强迫行为（反复做某事）</td></tr><tr><td>举例</td><td>反复洗手、反复检查门锁</td></tr><tr><td>辅导方法</td><td>暴露与反应预防、认知疗法</td></tr></tbody></table><h3 id="恐惧症" tabindex="-1">恐惧症 <a class="header-anchor" href="#恐惧症" aria-label="Permalink to &quot;恐惧症&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>表现</td><td>对特定对象或情境产生强烈恐惧</td></tr><tr><td>类型</td><td>社交恐惧症、广场恐惧症、特定恐惧症</td></tr><tr><td>辅导方法</td><td>系统脱敏法 🔴</td></tr></tbody></table><h3 id="网络成瘾-🔴" tabindex="-1">网络成瘾 🔴 <a class="header-anchor" href="#网络成瘾-🔴" aria-label="Permalink to &quot;网络成瘾 🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>内容</th></tr></thead><tbody><tr><td>判断标准</td><td>上网时间过长、无法控制、影响正常生活</td></tr><tr><td>辅导方法</td><td>行为契约法、时间管理、替代活动</td></tr></tbody></table><hr><h2 id="_6-3-心理辅导方法-🔴🔴" tabindex="-1">6.3 心理辅导方法 🔴🔴 <a class="header-anchor" href="#_6-3-心理辅导方法-🔴🔴" aria-label="Permalink to &quot;6.3 心理辅导方法 🔴🔴&quot;">​</a></h2><h3 id="主要辅导方法" tabindex="-1">主要辅导方法 <a class="header-anchor" href="#主要辅导方法" aria-label="Permalink to &quot;主要辅导方法&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>核心技术</th><th>适用问题</th><th>关键人物</th></tr></thead><tbody><tr><td>系统脱敏法 🔴🔴</td><td>逐步暴露+放松训练</td><td>恐惧症、焦虑症</td><td>沃尔普</td></tr><tr><td>合理情绪疗法 🔴🔴</td><td>ABC理论，改变不合理信念</td><td>各种情绪问题</td><td>埃利斯</td></tr><tr><td>来访者中心疗法</td><td>无条件积极关注+真诚+共情</td><td>自我成长问题</td><td>罗杰斯</td></tr><tr><td>行为契约法</td><td>约定行为目标和奖惩</td><td>行为矫正</td><td>—</td></tr><tr><td>代币法</td><td>好行为得代币，兑换奖励</td><td>行为塑造</td><td>—</td></tr></tbody></table><h3 id="abc-理论-🔴🔴🔴" tabindex="-1">ABC 理论 🔴🔴🔴 <a class="header-anchor" href="#abc-理论-🔴🔴🔴" aria-label="Permalink to &quot;ABC 理论 🔴🔴🔴&quot;">​</a></h3><p><strong>A（Activating events）</strong> — 诱发事件 <strong>B（Beliefs）</strong> — 信念（认知） <strong>C（Consequences）</strong> — 情绪和行为结果</p><p><strong>核心观点</strong>：不是事件 A 直接导致结果 C，而是信念 B 导致了 C。改变不合理信念 B，就能改变 C。</p><p><strong>常见不合理信念</strong> 🔴：</p><ol><li>绝对化要求 — &quot;我必须考满分&quot;</li><li>过分概括化 — &quot;一次失败=我是个失败者&quot;</li><li>糟糕至极 — &quot;考砸了=一切都完了&quot;</li></ol><p><strong>举例</strong>：</p><ul><li>事件A：考试没考好</li><li>不合理信念B：&quot;我太笨了，什么都做不好&quot;</li><li>结果C：抑郁、放弃</li><li>合理信念B&#39;：这次没考好，我可以找到原因下次改进</li><li>结果C&#39;：积极面对、继续努力</li></ul><h3 id="心理辅导原则-🔴" tabindex="-1">心理辅导原则 🔴 <a class="header-anchor" href="#心理辅导原则-🔴" aria-label="Permalink to &quot;心理辅导原则 🔴&quot;">​</a></h3><ol><li>面向全体学生 — 预防为主</li><li>预防与发展相结合</li><li>尊重与理解学生</li><li>学生主体性</li><li>个别化对待</li><li>整体性发展</li></ol><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><table tabindex="0"><thead><tr><th>知识点</th><th>要点</th></tr></thead><tbody><tr><td>焦虑症辅导</td><td>放松训练+系统脱敏</td></tr><tr><td>ABC理论</td><td>A事件→B信念→C结果，改变B改变C</td></tr><tr><td>不合理信念三类</td><td>绝对化、过分概括、糟糕至极</td></tr><tr><td>来访者中心三条件</td><td>无条件积极关注+真诚+共情</td></tr><tr><td>系统脱敏法</td><td>放松+逐步暴露</td></tr></tbody></table>',35)])])}const q=d(l,[["render",o]]);export{u as __pageData,q as default};
